// Inline: update-check-logic
const UPDATE_CMD = 'docker compose pull n8n && docker compose up -d n8n --no-deps';
const VALIDATE_CMD = 'docker exec -e N8N_RUNNERS_ENABLED=false -e N8N_RUNNERS_BROKER_PORT=5699 homelab-n8n n8n execute --id axeg30n8SVKlCW54';

function parseVersion(str) {
  const parts = String(str).split('.').map(Number);
  return { major: parts[0], minor: parts[1], patch: parts[2] };
}

function classifyUpdate(current, latest) {
  const c = parseVersion(current);
  const l = parseVersion(latest);
  if (l.major !== c.major) return 'major';
  if (l.minor !== c.minor) return 'minor';
  if (l.patch !== c.patch) return 'patch';
  return 'up-to-date';
}

function buildUpdateReport(current, latest) {
  const type = classifyUpdate(current, latest);
  return { type, current, latest, updateCommand: type === 'patch' ? UPDATE_CMD : null };
}

function buildGmailSubject(report) {
  if (report.type === 'patch') {
    return '[Homelab] n8n Patch verfuegbar: ' + report.current + ' -> ' + report.latest;
  }
  const label = report.type === 'minor' ? 'Minor-Update' : 'Major-Update';
  return '[Homelab] n8n ' + label + ': manuelle Pruefung noetig (' + report.current + ' -> ' + report.latest + ')';
}

function buildGmailBody(report) {
  const lines = [
    'n8n Update-Check',
    '',
    'Aktuell: ' + report.current,
    'Neu:     ' + report.latest,
    'Typ:     ' + report.type,
    '',
  ];
  if (report.type === 'patch') {
    lines.push(
      'Patch-Update kann sicher eingespielt werden.',
      '',
      '1. Update anwenden:',
      '   ' + report.updateCommand,
      '',
      '2. Validierung (nach Neustart):',
      '   ' + VALIDATE_CMD,
    );
  } else {
    lines.push(
      (report.type === 'minor' ? 'Minor' : 'Major') + '-Update erfordert manuelle Pruefung.',
      '',
      'Changelog pruefen: https://github.com/n8n-io/n8n/releases',
    );
  }
  return lines.join('\n');
}

// --- Read data from previous nodes ---
const hubItem = $('HTTP Request - Docker Hub n8n latest').item;
const n8nItem = $('HTTP Request - n8n Current Version').item;

const latest = String(hubItem.json.name || '').replace(/^v/, '');
const current = String(n8nItem.json.n8nVersion || '').replace(/^v/, '');

if (!latest || !current) {
  throw new Error('Konnte Versionen nicht abrufen: latest=' + latest + ' current=' + current);
}

const report = buildUpdateReport(current, latest);
return [{ json: {
  type: report.type,
  current: report.current,
  latest: report.latest,
  updateCommand: report.updateCommand,
  gmailSubject: buildGmailSubject(report),
  gmailBody: buildGmailBody(report),
  send: report.type !== 'up-to-date',
} }];
